/**
 * @file useWorkerToken.ts
 * @module v8/hooks
 * @description Custom hook for managing worker token state and operations
 * @version 3.0.0
 *
 * Extracted from MFAAuthenticationMainPageV8.tsx as part of V3 refactoring.
 * Centralizes all worker token-related logic including:
 * - Token status monitoring
 * - Token refresh/update
 * - Modal state management
 * - Configuration settings
 * - Event listeners for token updates
 */

import { useCallback, useEffect, useState } from 'react';
import { MFAConfigurationServiceV8 } from '@/v8/services/mfaConfigurationServiceV8';
import type { TokenStatusInfo } from '@/v8/services/workerTokenStatusServiceV8';
import { WorkerTokenStatusServiceV8 } from '@/v8/services/workerTokenStatusServiceV8';

export interface UseWorkerTokenConfig {
	/** Auto-refresh interval in milliseconds (default: 5000) */
	refreshInterval?: number;
	/** Enable auto-refresh when token is about to expire */
	enableAutoRefresh?: boolean;
}

export interface UseWorkerTokenReturn {
	// State
	tokenStatus: TokenStatusInfo;
	showWorkerTokenModal: boolean;
	silentApiRetrieval: boolean;
	showTokenAtEnd: boolean;
	isRefreshing: boolean;

	// Actions
	setShowWorkerTokenModal: (show: boolean) => void;
	setSilentApiRetrieval: (silent: boolean) => void;
	setShowTokenAtEnd: (show: boolean) => void;
	refreshTokenStatus: () => Promise<void>;
	checkAndRefreshToken: () => Promise<void>;

	// Computed
	showTokenOnly: boolean;
}

const MODULE_TAG = '[🔐 USE-WORKER-TOKEN]';

/**
 * Custom hook for managing worker token state and operations
 */
export const useWorkerToken = (config: UseWorkerTokenConfig = {}): UseWorkerTokenReturn => {
	const { refreshInterval = 5000, enableAutoRefresh = true } = config;

	// State
	const [tokenStatus, setTokenStatus] = useState<TokenStatusInfo>({
		status: 'missing',
		message: 'Checking worker token status...',
		isValid: false,
	});
	const [showWorkerTokenModal, setShowWorkerTokenModal] = useState(false);
	const [silentApiRetrieval, setSilentApiRetrieval] = useState(false);
	const [showTokenAtEnd, setShowTokenAtEnd] = useState(false);
	const [isRefreshing, setIsRefreshing] = useState(false);

	// Initialize token status
	useEffect(() => {
		const initializeTokenStatus = async () => {
			try {
				const status = await WorkerTokenStatusServiceV8.checkWorkerTokenStatus();
				setTokenStatus(status);
			} catch (error) {
				console.error(`${MODULE_TAG} Failed to initialize token status:`, error);
				setTokenStatus({
					status: 'missing',
					message: 'Failed to check worker token status',
					isValid: false,
				});
			}
		};

		initializeTokenStatus();
	}, []);

	// Load worker token settings from config service
	useEffect(() => {
		const loadConfig = () => {
			try {
				const config = MFAConfigurationServiceV8.loadConfiguration();
				setSilentApiRetrieval(config.workerToken.silentApiRetrieval);
				setShowTokenAtEnd(config.workerToken.showTokenAtEnd);
			} catch (error) {
				console.error(`${MODULE_TAG} Failed to load worker token config:`, error);
			}
		};

		loadConfig();
	}, []);

	// Refresh token status
	const refreshTokenStatus = useCallback(async () => {
		// Show immediate loading state for better UX
		setIsRefreshing(true);
		console.log(`${MODULE_TAG} Manual token refresh triggered - showing loading state`);

		try {
			const status = await WorkerTokenStatusServiceV8.checkWorkerTokenStatus();
			setTokenStatus(status);
			console.log(`${MODULE_TAG} Manual token refresh completed:`, status.status);
		} catch (error) {
			console.error(`${MODULE_TAG} Failed to refresh token status:`, error);
		} finally {
			// Hide loading state after refresh completes
			setIsRefreshing(false);
			console.log(`${MODULE_TAG} Manual token refresh completed - hiding loading state`);
		}
	}, []);

	// Update token status on events
	useEffect(() => {
		const handleTokenUpdate = async () => {
			// Show immediate loading state for better UX
			setIsRefreshing(true);
			console.log(`${MODULE_TAG} Token update triggered - showing loading state`);

			try {
				const status = await WorkerTokenStatusServiceV8.checkWorkerTokenStatus();
				setTokenStatus(status);
				console.log(`${MODULE_TAG} Token status updated:`, status.status);
			} catch (error) {
				console.error(`${MODULE_TAG} Failed to check token status in event handler:`, error);
			} finally {
				// Hide loading state after update completes
				setIsRefreshing(false);
				console.log(`${MODULE_TAG} Token update completed - hiding loading state`);
			}
		};

		// Handle storage events more carefully - only respond to worker token related changes
		const handleStorageChange = (event: StorageEvent) => {
			// Only process storage events related to worker token
			if (
				event.key &&
				(event.key.includes('worker_token') ||
					event.key.includes('unified_worker_token') ||
					event.key.includes('worker_credentials'))
			) {
				console.log(`${MODULE_TAG} Worker token related storage change detected:`, event.key);
				handleTokenUpdate();
			}
		};

		window.addEventListener('workerTokenUpdated', handleTokenUpdate);
		window.addEventListener('storage', handleStorageChange);
		const interval = setInterval(handleTokenUpdate, refreshInterval);

		return () => {
			window.removeEventListener('workerTokenUpdated', handleTokenUpdate);
			window.removeEventListener('storage', handleStorageChange);
			clearInterval(interval);
		};
	}, [refreshInterval]);

	// Auto-refresh worker token when it's about to expire
	const checkAndRefreshToken = useCallback(async () => {
		if (!enableAutoRefresh) return;

		try {
			const config = MFAConfigurationServiceV8.loadConfiguration();
			if (!config.workerToken.silentApiRetrieval) {
				console.log(`${MODULE_TAG} Silent API retrieval disabled, skipping auto-refresh`);
				return;
			}

			const status = await WorkerTokenStatusServiceV8.checkWorkerTokenStatus();
			console.log(`${MODULE_TAG} Checking token for auto-refresh:`, {
				status: status.status,
				isValid: status.isValid,
				expiresAt: status.expiresAt,
				silentApiRetrieval: config.workerToken.silentApiRetrieval,
			});

			// If token expires in less than 5 minutes, refresh it
			if (status.expiresAt) {
				const expiresIn = status.expiresAt - Date.now();
				const fiveMinutes = 5 * 60 * 1000;

				if (expiresIn > 0 && expiresIn < fiveMinutes && !isRefreshing) {
					setIsRefreshing(true);
					console.log(
						`${MODULE_TAG} Token expiring in ${Math.round(expiresIn / 1000)}s, auto-refreshing...`
					);

					// Trigger silent token retrieval directly
					const { tokenGatewayV8 } = await import('@/v8/services/auth/tokenGatewayV8');
					const result = await tokenGatewayV8.getWorkerToken({
						mode: 'silent',
						forceRefresh: true,
						timeout: 10000,
						maxRetries: 2,
					});

					const success = result.success;

					if (success) {
						console.log(`${MODULE_TAG} Auto-refresh successful`);
					} else {
						console.warn(`${MODULE_TAG} Auto-refresh failed, user interaction may be required`);
					}

					// Wait a bit then check status again
					setTimeout(async () => {
						await refreshTokenStatus();
						setIsRefreshing(false);
					}, 2000);
				} else if (expiresIn <= 0) {
					console.log(`${MODULE_TAG} Token expired, attempting refresh...`);
					setIsRefreshing(true);

					// Trigger silent token retrieval for expired token
					const { tokenGatewayV8 } = await import('@/v8/services/auth/tokenGatewayV8');
					const result = await tokenGatewayV8.getWorkerToken({
						mode: 'silent',
						forceRefresh: true,
						timeout: 10000,
						maxRetries: 2,
					});

					const success = result.success;

					if (success) {
						console.log(`${MODULE_TAG} Expired token refresh successful`);
					} else {
						console.warn(`${MODULE_TAG} Expired token refresh failed, user interaction required`);
					}

					setTimeout(async () => {
						await refreshTokenStatus();
						setIsRefreshing(false);
					}, 2000);
				}
			} else if (!status.isValid) {
				console.log(`${MODULE_TAG} Token invalid, attempting refresh...`);
				setIsRefreshing(true);

				// Trigger silent token retrieval for invalid token
				const { tokenGatewayV8 } = await import('@/v8/services/auth/tokenGatewayV8');
				const result = await tokenGatewayV8.getWorkerToken({
					mode: 'silent',
					forceRefresh: true,
					timeout: 10000,
					maxRetries: 2,
				});

				const success = result.success;

				if (success) {
					console.log(`${MODULE_TAG} Invalid token refresh successful`);
				} else {
					console.warn(`${MODULE_TAG} Invalid token refresh failed, user interaction required`);
				}

				setTimeout(async () => {
					await refreshTokenStatus();
					setIsRefreshing(false);
				}, 2000);
			}
		} catch (error) {
			console.error(`${MODULE_TAG} Failed to check/refresh token:`, error);
			setIsRefreshing(false);
		}
	}, [enableAutoRefresh, isRefreshing, refreshTokenStatus]);

	// Auto-refresh check interval
	useEffect(() => {
		if (!enableAutoRefresh) return;

		const interval = setInterval(checkAndRefreshToken, 60000); // Check every minute
		return () => clearInterval(interval);
	}, [enableAutoRefresh, checkAndRefreshToken]);

	// Compute showTokenOnly for modal
	const showTokenOnly = (() => {
		if (!showWorkerTokenModal) return false;
		try {
			const config = MFAConfigurationServiceV8.loadConfiguration();
			return config.workerToken.showTokenAtEnd && tokenStatus.isValid;
		} catch {
			return false;
		}
	})();

	return {
		// State
		tokenStatus,
		showWorkerTokenModal,
		silentApiRetrieval,
		showTokenAtEnd,
		isRefreshing,

		// Actions
		setShowWorkerTokenModal,
		setSilentApiRetrieval,
		setShowTokenAtEnd,
		refreshTokenStatus,
		checkAndRefreshToken,

		// Computed
		showTokenOnly,
	};
};
